def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 6):
            weight = (6 - j) / 15
            term = ratio ** j
            if j % 2 == 0:
                term *= (1 + 0.1 * j)
            else:
                term *= (1 - 0.05 * j)
            score += weight * term
        if capacity > 3 * item:
            score *= 0.4
        elif capacity > 2 * item:
            score *= 0.6
        elif capacity > 1.5 * item:
            score *= 0.8
        else:
            score *= 1.2
        if capacity < 1.2 * item:
            score *= 1.5
        elif capacity < item:
            score *= 2.5
        diff = capacity - item
        if diff > 0:
            for k in range(1, 4):
                score += (0.05 / k) * np.exp(-diff * k)
        else:
            for k in range(1, 4):
                score += (0.1 * k) * np.exp(diff * k)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 10
    min_p = np.min(priorities)
    max_p = np.max(priorities)
    if max_p != min_p:
        priorities = (priorities - min_p) / (max_p - min_p)
    else:
        priorities = np.zeros_like(priorities)
    return priorities
